#!/usr/bin/env node
/**
 * generate-skills-registry.mjs — Skills Registry inventory generator
 *
 * AUTO-GENERATED output — do NOT hand-edit skills-registry.json.
 * This script is the SSOT. Edit skill.json files in _RPI_STANDARDS/skills/<name>/
 * and re-run this script to regenerate.
 *
 * Usage: node scripts/generate-skills-registry.mjs
 *
 * Emits:
 *   _RPI_STANDARDS/skills-registry.json  — machine inventory
 *   _RPI_STANDARDS/skills-registry.html  — human surface (auto-mounts on roadmaps)
 */

import { readFileSync, writeFileSync, readdirSync, statSync, existsSync } from 'node:fs'
import { join, dirname } from 'node:path'
import { fileURLToPath } from 'node:url'

const __dirname = dirname(fileURLToPath(import.meta.url))
const STANDARDS_ROOT = dirname(__dirname)
const SKILLS_DIR = join(STANDARDS_ROOT, 'skills')
const REGISTRY_JSON = join(STANDARDS_ROOT, 'skills-registry.json')
const REGISTRY_HTML = join(STANDARDS_ROOT, 'skills-registry.html')

// Collect all skills by scanning skills/*/skill.json
const skills = []

if (!existsSync(SKILLS_DIR)) {
  console.error(`❌ Skills dir not found: ${SKILLS_DIR}`)
  process.exit(1)
}

for (const entry of readdirSync(SKILLS_DIR)) {
  const skillDir = join(SKILLS_DIR, entry)
  if (!statSync(skillDir).isDirectory()) continue

  const jsonPath = join(skillDir, 'skill.json')
  const skillMdPath = join(skillDir, 'SKILL.md')
  const gatesMdPath = join(skillDir, 'gates.md')
  const surfacePath = join(skillDir, 'surface.html')

  if (!existsSync(jsonPath)) {
    console.warn(`⚠️  Skipping ${entry} — no skill.json found`)
    continue
  }

  let meta
  try {
    meta = JSON.parse(readFileSync(jsonPath, 'utf8'))
  } catch (e) {
    console.warn(`⚠️  Skipping ${entry} — invalid skill.json: ${e.message}`)
    continue
  }

  // Validate required fields
  const required = ['id', 'owner_warrior', 'lane', 'version']
  const missing = required.filter(f => !meta[f])
  if (missing.length) {
    console.warn(`⚠️  Skipping ${entry} — skill.json missing: ${missing.join(', ')}`)
    continue
  }

  skills.push({
    ...meta,
    _files: {
      skill_md: existsSync(skillMdPath),
      gates_md: existsSync(gatesMdPath),
      surface_html: existsSync(surfacePath),
    },
    _path: `skills/${entry}/`,
  })
}

skills.sort((a, b) => a.id.localeCompare(b.id))

// Emit JSON registry
const registry = {
  _note: 'AUTO-GENERATED by scripts/generate-skills-registry.mjs — do NOT hand-edit',
  generated_at: new Date().toISOString(),
  count: skills.length,
  skills,
}
writeFileSync(REGISTRY_JSON, JSON.stringify(registry, null, 2))
console.log(`✅ skills-registry.json — ${skills.length} skill(s)`)

// Emit HTML surface
const rows = skills.map(s => `
  <tr>
    <td><strong>${s.name || s.id}</strong><br><code>/${s.id}</code></td>
    <td>${s.owner_warrior}</td>
    <td>${s.lane}</td>
    <td>${s.version}</td>
    <td>${(s.hooks_enforcing || []).map(h => `<code>${h}</code>`).join('<br>') || '—'}</td>
    <td>${s.mcps_called?.length ? s.mcps_called.join(', ') : '—'}</td>
    <td>${s.born || '—'}</td>
  </tr>`).join('')

const html = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Skills Registry · RPI Standards</title>
<style>
:root{--bg:#0a0e17;--card:#111827;--card2:#1a2236;--border:#1e293b;--text:#e2e8f0;--muted:#94a3b8;--green:#22c55e;--blue:#3b82f6;--cyan:#06b6d4}
*{margin:0;padding:0;box-sizing:border-box}
body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',system-ui,sans-serif;background:var(--bg);color:var(--text);line-height:1.5;max-width:1100px;margin:0 auto;padding:28px 20px}
h1{font-size:1.5rem;font-weight:800;background:linear-gradient(135deg,var(--blue),var(--cyan));-webkit-background-clip:text;-webkit-text-fill-color:transparent;margin-bottom:6px}
.meta{color:var(--muted);font-size:0.82rem;margin-bottom:20px}
table{width:100%;border-collapse:collapse;font-size:0.86rem}
th{text-align:left;padding:9px 12px;background:var(--card2);color:var(--muted);font-weight:600;font-size:0.75rem;text-transform:uppercase;letter-spacing:1px;border-bottom:2px solid var(--border)}
td{padding:9px 12px;border-bottom:1px solid var(--border);vertical-align:top}
code{font-size:0.8rem;background:rgba(59,130,246,0.1);color:var(--blue);padding:1px 5px;border-radius:4px;font-family:monospace}
.footer{color:var(--muted);font-size:0.75rem;margin-top:22px;padding-top:12px;border-top:1px solid var(--border)}
</style>
</head>
<body>
<h1>Skills Registry</h1>
<div class="meta">AUTO-GENERATED · ${new Date().toISOString()} · ${skills.length} skill(s) · <code>scripts/generate-skills-registry.mjs</code></div>
<table>
  <thead>
    <tr>
      <th>Skill / Invoke</th>
      <th>Owner</th>
      <th>Lane</th>
      <th>Version</th>
      <th>Enforcing hooks</th>
      <th>MCPs called</th>
      <th>Born</th>
    </tr>
  </thead>
  <tbody>${rows}</tbody>
</table>
<div class="footer">Skills Registry · _RPI_STANDARDS · MCP → Skill → Hook · SKILLS-REG-001 · #RunningOurOwnRACE</div>
</body>
</html>`

writeFileSync(REGISTRY_HTML, html)
console.log(`✅ skills-registry.html`)
console.log(`\nDone — ${skills.length} skill(s) registered.`)
